### Swift Generics

Generics allow you to write flexible, reusable functions and types that can work with any type. They are one of Swift's most powerful features for writing type-safe, non-repetitive code.

**Generic Functions:**

```swift
func swapValues<T>(_ a: inout T, _ b: inout T) {
    let temp = a
    a = b
    b = temp
}

var x = 10, y = 20
swapValues(&x, &y)
print("x: \(x), y: \(y)")  // x: 20, y: 10

var firstName = "Alice", lastName = "Bob"
swapValues(&firstName, &lastName)
print(firstName, lastName)  // Bob Alice
```

**Generic Types:**

```swift
struct Stack<Element> {
    private var items: [Element] = []

    mutating func push(_ item: Element) {
        items.append(item)
    }

    mutating func pop() -> Element? {
        items.popLast()
    }

    var peek: Element? { items.last }
    var isEmpty: Bool { items.isEmpty }
}

var intStack = Stack<Int>()
intStack.push(1)
intStack.push(2)
print(intStack.pop() ?? 0)  // 2

var stringStack = Stack<String>()
stringStack.push("Hello")
stringStack.push("World")
print(stringStack.pop() ?? "")  // World
```

**Generic Type Parameters:**

| Convention | Meaning |
|------------|---------|
| `T` | Type (most common) |
| `U`, `V` | Second, third types |
| `T1`, `T2` | Multiple types |
| `Key`, `Value` | Descriptive names |
| `Element` | Collection element |

```swift
// Multiple type parameters
struct Pair<Key, Value> {
    let key: Key
    let value: Value
}

let pair = Pair(key: "name", value: "Alice")
```

**Generic Extensions:**

```swift
extension Stack {
    var top: Element? { items.last }

    mutating func pushAll(_ newItems: [Element]) {
        for item in newItems {
            push(item)
        }
    }
}

extension Stack where Element: Equatable {
    func contains(_ item: Element) -> Bool {
        items.contains(item)
    }
}
```

> **Key Point:** Generic code prevents duplication while maintaining type safety. The compiler creates specialized versions of generic code for each type used.

Use type parameters (like `T`) as placeholders. When the function or type is used, the actual type is substituted automatically.

codeExample:
import Foundation

// Generic function
func findIndex<T: Equatable>(of valueToFind: T, in array: [T]) -> Int? {
    for (index, value) in array.enumerated() {
        if value == valueToFind {
            return index
        }
    }
    return nil
}

let numbers = [10, 20, 30, 40, 50]
if let index = findIndex(of: 30, in: numbers) {
    print("Found at index \(index)")
}

let names = ["Alice", "Bob", "Charlie"]
if let index = findIndex(of: "Bob", in: names) {
    print("Found at index \(index)")
}

// Generic type
struct Queue<Element> {
    private var items: [Element] = []

    mutating func enqueue(_ item: Element) {
        items.append(item)
    }

    mutating func dequeue() -> Element? {
        guard !items.isEmpty else { return nil }
        return items.removeFirst()
    }

    var count: Int { items.count }
}

var queue = Queue<String>()
queue.enqueue("First")
queue.enqueue("Second")
print(queue.dequeue() ?? "")  // First
print(queue.dequeue() ?? "")  // Second
